if (!s) return str_dup("");
const char *start = s;
while (*start && (*start == ' ' || *start == '\t' || *start == '\n' || *start == '\r')) start++;
const char *end = s + strlen(s);
while (end > start && (end[-1] == ' ' || end[-1] == '\t' || end[-1] == '\n' || end[-1] == '\r')) end--;
size_t len = (size_t)(end - start);
char *out = (char *)malloc(len + 1);
if (!out) return NULL;
memcpy(out, start, len);
out[len] = '\0';
return out;
